// OpenTelemetry observer for the receiver's onEvent stream. Duck-typed against
// the OpenTelemetry JS API (Meter/Tracer) so this package takes no hard OTel
// dependency — callers wire their application's meter/tracer, exactly like the
// Postgres task store accepts any `{query}` without depending on `pg`.
//
//   import { metrics, trace } from "@opentelemetry/api";
//   const onEvent = createOtelObserver({
//     meter: metrics.getMeter("portauth-a2a"),
//     tracer: trace.getTracer("portauth-a2a"), // optional
//   });
//   createPortAuthReceiver({ onEvent });
//
// The meter must expose createCounter(name)/createHistogram(name); the optional
// tracer must expose startSpan(name, options). Both follow the standard API.

export function createOtelObserver({ meter, tracer = null } = {}) {
  if (!meter || typeof meter.createCounter !== "function" || typeof meter.createHistogram !== "function") {
    throw new Error("createOtelObserver requires an OpenTelemetry Meter (createCounter/createHistogram)");
  }

  const decisions = meter.createCounter("portauth.a2a.decisions", { description: "Authorization decisions by outcome." });
  const rejected = meter.createCounter("portauth.a2a.rejected", { description: "Requests rejected before engine evaluation." });
  const replays = meter.createCounter("portauth.a2a.replays", { description: "Idempotent replays served from the task store." });
  const inProgress = meter.createCounter("portauth.a2a.in_progress", { description: "Duplicate requests observed while the first is pending." });
  const persistenceFailures = meter.createCounter("portauth.a2a.persistence_failures", { description: "Task persistence failures by phase." });
  const engineDuration = meter.createHistogram("portauth.a2a.engine_call.duration", { unit: "ms", description: "PortAuth engine call latency." });
  const requestDuration = meter.createHistogram("portauth.a2a.request.duration", { unit: "ms", description: "End-to-end receiver request latency." });

  return function otelObserver(event = {}) {
    if (!event || typeof event !== "object") return;

    if (typeof event.engineDurationMs === "number") {
      engineDuration.record(event.engineDurationMs, attrs(event));
    }
    if (typeof event.durationMs === "number") {
      requestDuration.record(event.durationMs, attrs(event));
    }

    switch (event.type) {
      case "decision":
        decisions.add(1, { decision: event.decision || "unknown" });
        emitSpan(tracer, "portauth.a2a.decision", event);
        break;
      case "rejected":
        rejected.add(1, { reason: event.reason || "unknown" });
        emitSpan(tracer, "portauth.a2a.rejected", event, "error");
        break;
      case "replay":
        replays.add(1, {});
        break;
      case "in_progress":
        inProgress.add(1, {});
        break;
      case "persistence_failed":
        persistenceFailures.add(1, { phase: event.phase || "unknown" });
        break;
      default:
        break;
    }
  };
}

// Attributes common to every signal. requestId is the correlation key shared
// with the X-Request-Id response/engine header.
function attrs(event) {
  const out = {};
  if (event.requestId) out["portauth.request_id"] = event.requestId;
  if (event.auditRecordId) out["portauth.audit_record_id"] = event.auditRecordId;
  return out;
}

// Emit a retrospective span for a terminal event. The observer runs after the
// decision is made, so the span's start time is reconstructed from durationMs to
// give trace backends a real-duration span correlated by requestId. Best-effort:
// any tracer/span API mismatch is swallowed so telemetry can't break requests.
function emitSpan(tracer, name, event, status) {
  if (!tracer || typeof tracer.startSpan !== "function") return;
  try {
    const endTime = Date.now();
    const startTime = typeof event.durationMs === "number" ? endTime - event.durationMs : endTime;
    const span = tracer.startSpan(name, { startTime });
    if (!span) return;
    span.setAttribute?.("portauth.request_id", event.requestId);
    span.setAttribute?.("portauth.task_id", event.taskId);
    if (event.decision) span.setAttribute?.("portauth.decision", event.decision);
    if (event.reason) span.setAttribute?.("portauth.reason", event.reason);
    if (event.auditRecordId) span.setAttribute?.("portauth.audit_record_id", event.auditRecordId);
    if (status === "error") span.setStatus?.({ code: 2 }); // SpanStatusCode.ERROR
    span.end?.(endTime);
  } catch {
    // Telemetry must never break request handling.
  }
}
